/*
 * Progressive-enhancement reconciliation for the "evento in evidenza"
 * spotlight on /eventi.
 *
 * The static build already bakes in the correct featured event using the
 * clock at build time (see scripts/select-featured-event.mjs). This script
 * exists only to cover the gap between deploys: if the site has not been
 * rebuilt since an event ended, the visitor's own clock is used to check
 * whether the baked-in pick is still correct, and if not, swap in the
 * matching pre-rendered alternate that was generated by the same build
 * script and embedded on this page.
 *
 * Rules respected:
 * - no network requests (the manifest and every alternate are already in
 *   the page, embedded at build time);
 * - no dependencies;
 * - no random selection and no invented content (every alternate is
 *   server-rendered HTML, not generated here);
 * - if build-time and runtime agree, which is the common case right after
 *   a deploy, the DOM is left untouched and nothing flickers;
 * - if anything is missing or malformed, this script does nothing and the
 *   server-rendered, build-time-correct section stays exactly as it is.
 */
(function () {
  "use strict";

  function pickFeaturedEvent(events, todayIso) {
    var current = events
      .filter(function (event) {
        return event.startDate <= todayIso && todayIso <= event.endDate;
      })
      .sort(function (a, b) {
        return a.startDate < b.startDate ? -1 : a.startDate > b.startDate ? 1 : 0;
      });
    if (current.length > 0) return current[0];

    var future = events
      .filter(function (event) {
        return event.startDate > todayIso;
      })
      .sort(function (a, b) {
        return a.startDate < b.startDate ? -1 : a.startDate > b.startDate ? 1 : 0;
      });
    if (future.length > 0) return future[0];

    return null;
  }

  function run() {
    var section = document.getElementById("evento-in-evidenza");
    var manifestEl = document.getElementById("featured-event-manifest");
    var alternatesEl = document.getElementById("featured-event-alternates");
    if (!section || !manifestEl || !alternatesEl) return;

    var events;
    try {
      events = JSON.parse(manifestEl.textContent);
    } catch (err) {
      return;
    }
    if (!Array.isArray(events) || events.length === 0) return;

    var todayIso = new Date().toISOString().slice(0, 10);
    var winner = pickFeaturedEvent(events, todayIso);
    var winnerId = winner ? winner.id : "fallback";
    var currentId = section.getAttribute("data-event-id");

    if (winnerId === currentId) return;

    var template = alternatesEl.querySelector('template[data-event-id="' + winnerId + '"]');
    if (!template || !template.content) return;

    section.innerHTML = "";
    section.appendChild(template.content.cloneNode(true));
    section.setAttribute("data-event-id", winnerId);
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", run);
  } else {
    run();
  }
})();
